DROP TABLE IF EXISTS `tank_dictionary`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tank_dictionary` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `vehicle_code` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `display_name_ru` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `display_name_en` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `nation` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `tank_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `tier` int unsigned DEFAULT NULL,
  `is_premium` tinyint(1) DEFAULT '0',
  `is_collectible` tinyint(1) DEFAULT '0',
  `is_moderated` tinyint(1) DEFAULT '0',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `vehicle_code` (`vehicle_code`),
  KEY `idx_vehicle_code` (`vehicle_code`),
  KEY `idx_nation` (`nation`),
  KEY `idx_tier` (`tier`)
) ENGINE=InnoDB AUTO_INCREMENT=1546 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

