--
-- Table structure for table `tournament_brackets`
--

DROP TABLE IF EXISTS `tournament_brackets`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tournament_brackets` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `public_id` varchar(16) COLLATE utf8mb4_unicode_ci NOT NULL,
  `user_id` int unsigned DEFAULT NULL,
  `edit_token` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `title` varchar(120) COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text COLLATE utf8mb4_unicode_ci,
  `format` enum('single','double','group','group_se','group_de') COLLATE utf8mb4_unicode_ci NOT NULL,
  `match_format` enum('bo1','bo3','bo7','bo9') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'bo1',
  `game` enum('wot','csgo','dota2') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'wot',
  `game_realm` enum('ru','eu','na','asia') COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `visibility` enum('public','hidden') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'public',
  `status` enum('active','hidden') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'active',
  `moderation_note` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `moderated_by` int unsigned DEFAULT NULL,
  `moderated_at` timestamp NULL DEFAULT NULL,
  `bracket_data` json NOT NULL,
  `starts_at` datetime DEFAULT NULL,
  `completed_at` datetime DEFAULT NULL,
  `prize_pool` json DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_public_id` (`public_id`),
  KEY `idx_user` (`user_id`),
  KEY `idx_status_visibility_updated` (`status`,`visibility`,`updated_at`)
) ENGINE=InnoDB AUTO_INCREMENT=20 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

