_count_coefficient\": 0.4, \"damage_assisted_stun_avg\": 0, \"survived_battles_percent\": 20.51, \"damage_blocked_coefficient\": 0.18}','{\"data\": [[\"duelist\", false, \"special\", \"repeatable\", \"Duelist\", \"Destroy at least 2 enemy vehicles that caused damage to your vehicle in the battle.\", \"• Damage to modules is included.\\n• Ricochets and non-penetrating hits are not included.\\n• Can be obtained in Random Battles only.\", \"\", \"wot/current/achievement/duelist.png\", \"wot/current/achievement/big/duelist.png\", 1], [\"shootToKill\", false, \"special\", \"repeatable\", \"Fire for Effect\", \"Cause more damage to enemy vehicles than the hit points of your vehicle.\", \"• Damage caused by ramming or setting enemy vehicle on fire is included.\\n• Unavailable for SPGs.\\n• Can be obtained in Random Battles only.\", \"\", \"wot/current/achievement/shootToKill.png\", \"wot/current/achievement/big/shootToKill.png\", 10], [\"armorPiercer\", false, \"special\", \"series\", \"Master Gunner\", \"Score at least 5 armor-penetrating hits in a row against enemy vehicles.\", \"• A series is broken by a miss, non-penetration, or ricochet.\\n• The series can carry over to the next battle using the same vehicle.\\n• Every vehicle has its own series. Only the longest series is counted.\\n• Non-penetrating hits by HE shells that caused damage are not counted and interrupt the series.\\n• Can be obtained in Random Battles only.\", \"\", \"wot/current/achievement/armorPiercer.png\", \"wot/current/achievement/big/armorPiercer.png\", 5], [\"medalCarius\", false, \"class\", \"class\", \"Carius\'s Medal Class IV\", \"For the number of enemy vehicles destroyed.\", \"\", \"Otto Carius was one of the most successful tank aces of WWII. He commanded the Pz.Kpfw. 38(t), the Pz.Kpfw. VI Tiger, and the Jagdtiger tank destroyer during his impressive career.\", \"wot/current/achievement/medalCarius4.png\", \"wot/current/achievement/big/medalCarius4.png\", 4], [\"medalKnispel\", false, \"class\", \"class\", \"Knispel\'s Medal Class IV\", \"For the total amount of damage caused and received.\", \"\", \"Kurt Knispel, a WWII German tank ace, participated in battles on both the Western and Eastern Fronts, fighting in Pz.Kpfw. II, Pz.Kpfw. III, Pz.Kpfw. IV, Pz.Kpfw. VI Tiger, and Pz.Kpfw. VI Ausf. B Tiger II.\", \"wot/current/achievement/medalKnispel4.png\", \"wot/current/achievement/big/medalKnispel4.png\", 4], [\"medalPoppel\", false, \"class\", \"class\", \"Popel\'s Medal Class IV\", \"For the number of enemy vehicles detected.\", \"\", \"Lieutenant General of Tank Forces Nikolay Popel, a Soviet military leader and political officer, organized a raid against the enemy rear using captured vehicles during the battle of Dubno (Ukraine) in the summer of 1941.\", \"wot/current/achievement/medalPoppel4.png\", \"wot/current/achievement/big/medalPoppel4.png\", 4], [\"medalAbrams\", false, \"class\", \"class\", \"Abrams\'s Medal Class IV\", \"For the total number of team victories in which the player survived the battle.\", \"\", \"General Creighton Abrams commanded U.S. armored forces during WWII and the Vietnam War, earning a reputation as an aggressive and successful commander.\", \"wot/current/achievement/medalAbrams4.png\", \"wot/current/achievement/big/medalAbrams4.png\", 4]], \"mastery\": {\"mastery_count\": 0, \"vehicles_count\": 16}, \"parameters\": [\"name\", \"deprecated\", \"section\", \"type\", \"mark\", \"description\", \"condition\", \"hero_info\", \"icon\", \"icon_big\", \"value\"], \"total_achievements_count\": 28, \"unique_achievements_count\": 10}','{\"spa_id\": 1016813263, \"summary\": {\"is_valid\": true, \"last_battle_at\": 1456088144}, \"nickname\": \"Sir2000\", \"clan_info\": [], \"reg_timestamp\": 1447012895}','2026-06-05 12:46:25','ok',NULL,'2026-06-05 12:46:25','2026-06-05 12:46:25'),('na',1044932391,'loh228_winner','loh228_winner','','','{\"wtr\": null, \"xp_max\": 0, \"frags_max\": 0, \"damage_max\": 0, \"wins_ratio\": 0, \"blocked_