percent\": 66.67, \"battles_count_percent\": 0.04}, \"usa\": {\"wins_count\": 336, \"master_count\": 2, \"battles_count\": 592, \"wins_count_percent\": 56.76, \"battles_count_percent\": 7.34}, \"ussr\": {\"wins_count\": 2889, \"master_count\": 26, \"battles_count\": 5865, \"wins_count_percent\": 49.26, \"battles_count_percent\": 72.72}, \"china\": {\"wins_count\": 1, \"master_count\": 1, \"battles_count\": 1, \"wins_count_percent\": 100, \"battles_count_percent\": 0.01}, \"japan\": {\"wins_count\": 0, \"master_count\": 0, \"battles_count\": 1, \"wins_count_percent\": 0, \"battles_count_percent\": 0.01}, \"france\": {\"wins_count\": 731, \"master_count\": 14, \"battles_count\": 1512, \"wins_count_percent\": 48.35, \"battles_count_percent\": 18.75}, \"germany\": {\"wins_count\": 50, \"master_count\": 1, \"battles_count\": 91, \"wins_count_percent\": 54.95, \"battles_count_percent\": 1.13}}, \"frags_max\": 9, \"damage_max\": 5681, \"wins_count\": 4819, \"losses_count\": 4718, \"stun_num_avg\": 0, \"battles_count\": 9655, \"master_levels\": {\"1\": 3, \"2\": 15, \"3\": 14, \"4\": 13}, \"xp_amount_avg\": 382, \"capture_points\": 10868, \"frags_count_avg\": 0.81, \"damage_dealt_avg\": 669, \"survived_battles\": 2436, \"spotted_count_avg\": 1.41, \"damage_coefficient\": 0.86, \"wins_count_percent\": 49.91, \"damage_assisted_avg\": 77, \"damage_received_avg\": 779, \"master_level_counts\": {\"1\": 4, \"2\": 17, \"3\": 14, \"4\": 17}, \"losses_count_percent\": 48.87, \"dropped_capture_points\": 4923, \"frags_count_coefficient\": 1.08, \"damage_assisted_stun_avg\": 0, \"survived_battles_percent\": 25.23, \"damage_blocked_coefficient\": 0.47}','{\"data\": [[\"warrior\", false, \"battle\", \"repeatable\", \"«Воин»\", \"Уничтожить машин противника:\\n    6 и более — Стандартный бой, Штурм, Встречный бой.\\n    8 и более — Генеральное сражение.\", \"• Выдаётся только в Случайных боях.\", \"\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/warrior.png\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/big/warrior.png\", 62], [\"mainGun\", false, \"battle\", \"repeatable\", \"«Основной калибр»\", \"Нанести наибольшее количество урона за бой.\", \"• Нанесённый урон должен составлять не менее 20% от суммарной прочности техники противника.\\n• Нанесённый урон должен составлять не менее 1000 единиц.\\n• Нельзя задевать союзников прямыми выстрелами.\\n• Выдаётся только в Случайных боях.\", \"\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/mainGun.png\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/big/mainGun.png\", 2], [\"supporter\", false, \"battle\", \"repeatable\", \"«Поддержка»\", \"Нанести урон или критические попадания наибольшему количеству машин противника, но не менее 6.\", \"• Засчитываются цели, которые впоследствии были уничтожены другими игроками или самоуничтожились.\\n• Рикошеты и непробития не учитываются.\\n• Выдаётся только в Случайных боях.\", \"\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/supporter.png\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/big/supporter.png\", 23], [\"sniper2\", false, \"battle\", \"repeatable\", \"«Танкист-снайпер»\", \"Нанести наибольшее количество урона за бой с дистанции не менее 300 метров.\", \"• Произвести не менее 8 выстрелов.\\n• Общая точность стрельбы за бой — не менее 85%.\\n• Не менее 80% попаданий должны быть с пробитием брони.\\n• Нанесённого с расстояния свыше 300 метров урона должно быть больше очков прочности машины игрока и не менее 1000.\\n• Нельзя задевать союзников прямыми выстрелами.\\n• Не выдаётся при игре на САУ.\\n• Выдаётся только в Случайных боях.\", \"\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/sniper2.png\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/big/sniper2.png\", 1], [\"reliableComrade\", true, \"action\", \"repeatable\", \"«Надёжный боевой товарищ»\", \"Не наносить союзникам никакого урона в течение 50 боёв.\", \"• Урон по модулям, не выведший их из строя, не учитывается.\\n• Рикошеты и непробития не учитываются.\\n• Серия прерывается любыми действиями, снизившими прочность машины союзника.\\n• Серия может продолжиться при игре на любой машине.\\n• Выдавалась только в Случайных боях.\\n• Выдавалась до выхода обновления 1.6.1.\", \"\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/reliableComrade.png\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/big/reliableComrade.png\", 1], [\"fighter\", false, \"special\", \"repeatable\", \"«Боец»\", \"Уничтожить 4-5 машин противника в одном бою.\", \"• Выдаётся только в Случайных боях.\", \"\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/fighter.png\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/big/fighter.png\", 7], [\"duelist\", false, \"special\", \"repeatable\", \"«Дуэлянт»\", \"Уничтожить в бою не менее 2 машин противника, нанёсших вам урон.\", \"• Повреждения модулей засчитываются.\\n• Рикошеты и непробития не засчитываются.\\n• Выдаётся только в Случайных боях.\", \"\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/duelist.png\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/big/duelist.png\", 13], [\"even\", false, \"memorial\", \"repeatable\", \"«В расчёте!»\", \"Уничтожить противника и быть уничтоженным им же.\", \"• Учитывается также уничтожение пожаром или тараном.\\n• Выдаётся только в Случайных боях.\", \"\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/even.png\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/big/even.png\", 2], [\"evileye\", false, \"battle\", \"repeatable\", \"«Дозорный»\", \"Предоставить разведданные, обеспечившие повреждение союзниками не менее 6 машин противника.\", \"• Засчитываются цели, разведданные по которым в момент их повреждения передавал только один игрок.\\n• Выдаётся только в Случайных боях.\", \"\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/evileye.png\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/big/evileye.png\", 11]], \"parameters\": [\"name\", \"deprecated\", \