nt\": 3, \"master_count\": 2, \"battles_count\": 5, \"wins_count_percent\": 60, \"battles_count_percent\": 0.05}, \"germany\": {\"wins_count\": 2300, \"master_count\": 28, \"battles_count\": 4588, \"wins_count_percent\": 50.13, \"battles_count_percent\": 45.31}}, \"frags_max\": 8, \"damage_max\": 5474, \"wins_count\": 5084, \"losses_count\": 4959, \"stun_num_avg\": 0, \"battles_count\": 10126, \"master_levels\": {\"1\": 11, \"2\": 24, \"3\": 32, \"4\": 27}, \"xp_amount_avg\": 491, \"capture_points\": 7612, \"frags_count_avg\": 0.88, \"damage_dealt_avg\": 917, \"survived_battles\": 2912, \"spotted_count_avg\": 0.8, \"damage_coefficient\": 1.33, \"wins_count_percent\": 50.21, \"damage_assisted_avg\": 271, \"damage_received_avg\": 689, \"master_level_counts\": {\"1\": 11, \"2\": 24, \"3\": 32, \"4\": 27}, \"losses_count_percent\": 48.97, \"dropped_capture_points\": 6413, \"frags_count_coefficient\": 1.24, \"damage_assisted_stun_avg\": 0, \"survived_battles_percent\": 28.76, \"damage_blocked_coefficient\": 0.25}','{\"data\": [[\"warrior\", false, \"battle\", \"repeatable\", \"«Воин»\", \"Уничтожить машин противника:\\n    6 и более — Стандартный бой, Штурм, Встречный бой.\\n    8 и более — Генеральное сражение.\", \"• Выдаётся только в Случайных боях.\", \"\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/warrior.png\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/big/warrior.png\", 34], [\"mainGun\", false, \"battle\", \"repeatable\", \"«Основной калибр»\", \"Нанести наибольшее количество урона за бой.\", \"• Нанесённый урон должен составлять не менее 20% от суммарной прочности техники противника.\\n• Нанесённый урон должен составлять не менее 1000 единиц.\\n• Нельзя задевать союзников прямыми выстрелами.\\n• Выдаётся только в Случайных боях.\", \"\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/mainGun.png\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/big/mainGun.png\", 183], [\"supporter\", false, \"battle\", \"repeatable\", \"«Поддержка»\", \"Нанести урон или критические попадания наибольшему количеству машин противника, но не менее 6.\", \"• Засчитываются цели, которые впоследствии были уничтожены другими игроками или самоуничтожились.\\n• Рикошеты и непробития не учитываются.\\n• Выдаётся только в Случайных боях.\", \"\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/supporter.png\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/big/supporter.png\", 79], [\"sniper2\", false, \"battle\", \"repeatable\", \"«Танкист-снайпер»\", \"Нанести наибольшее количество урона за бой с дистанции не менее 300 метров.\", \"• Произвести не менее 8 выстрелов.\\n• Общая точность стрельбы за бой — не менее 85%.\\n• Не менее 80% попаданий должны быть с пробитием брони.\\n• Нанесённого с расстояния свыше 300 метров урона должно быть больше очков прочности машины игрока и не менее 1000.\\n• Нельзя задевать союзников прямыми выстрелами.\\n• Не выдаётся при игре на САУ.\\n• Выдаётся только в Случайных боях.\", \"\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/sniper2.png\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/big/sniper2.png\", 10], [\"medalRadleyWalters\", false, \"epic\", \"repeatable\", \"Медаль Рэдли-Уолтерса\", \"Уничтожить машин противника:\\n    8-9 — Стандартный бой, Штурм, Встречный бой.\\n    10-12 — Генеральное сражение.\", \"• Управлять техникой V уровня и выше.\\n• Выдаётся только в Случайных боях.\", \"Сидней Валпи Рэдли-Уолтерс — канадский танковый ас 27-го танкового полка. На танке Sherman Firefly уничтожил восемнадцать немецких танков в 1944–1945 гг.\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/medalRadleyWalters.png\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/big/medalRadleyWalters.png\", 1], [\"reliableComrade\", true, \"action\", \"repeatable\", \"«Надёжный боевой товарищ»\", \"Не наносить союзникам никакого урона в течение 50 боёв.\", \"• Урон по модулям, не выведший их из строя, не учитывается.\\n• Рикошеты и непробития не учитываются.\\n• Серия прерывается любыми действиями, снизившими прочность машины союзника.\\n• Серия может продолжиться при игре на любой машине.\\n• Выдавалась только в Случайных боях.\\n• Выдавалась до выхода обновления 1.6.1.\", \"\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/reliableComrade.png\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/big/reliableComrade.png\", 76], [\"fighter\", false, \"special\", \"repeatable\", \"«Боец»\", \"Уничтожить 4-5 машин противника в одном бою.\", \"• Выдаётся только в Случайных боях.\", \"\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/fighter.png\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/big/fighter.png\", 322], [\"duelist\", false, \"special\", \"repeatable\", \"«Дуэлянт»\", \"Уничтожить в бою не менее 2 машин противника, нанёсших вам урон.\", \"• Повреждения модулей засчитываются.\\n• Рикошеты и непробития не засчитываются.\\n• Выдаётся только в Случайных боях.\", \"\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/duelist.png\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/big/duelist.png\", 279], [\"even\", false, \"memorial\", \"repeatable\", \"«В расчёте!»\", \"Уничтожить противника и быть уничтоженным им же.\", \"• Учитывается также уничтожение пожаром или тараном.\\n• Выдаётся только в Случайных боях.\", \"\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/even.png\", \"//dav-static.tanki.su//ptlru/mt/current/achievement/big/even.png\", 27]], \"parameters\": [\"name\", \"deprecated\", \"section\", \"type\", \"mark\", \"description\", \"condition\", \"hero_info\", \"icon\", \"icon_big\", \"value\"], \"action_achievements_count\": 11, \"common_achievements_count\": 60, \"available_achievements_count\": 125}','{\"spa_id\": 58115522, \"summary\": {\"is_valid\": true, \"last_battle_at\": 1486121599}, \"nickname\": \"Sergey\", \"clan_info\": [], \"reg_timestamp\": 1441352145}','2026-06-05 11:23:07','ok',NULL,'2026-06-05 11:21:32','2026-06-05 11:23:07'),(